import heapq

def a_star_pathfinding(grid, start, end):
    rows, cols = len(grid), len(grid[0])

    def heuristic(node, target):
        return abs(node[0] - target[0]) + abs(node[1] - target[1])

    def is_valid(r, c):
        return 0 <= r < rows and 0 <= c < cols and grid[r][c] == 0

    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    open_set = []
    heapq.heappush(open_set, (heuristic(start, end), start))

    came_from = {}

    g_score = {start: 0}
    f_score = {start: heuristic(start, end)}

    while open_set:
        current_f, current_node = heapq.heappop(open_set)

        if current_node in f_score and current_f > f_score[current_node]:
            continue

        if current_node == end:
            path = []
            temp_node = end
            while temp_node in came_from:
                path.append(temp_node)
                temp_node = came_from[temp_node]
            path.append(start)
            return path[::-1]

        for dr, dc in directions:
            neighbor = (current_node[0] + dr, current_node[1] + dc)

            if is_valid(neighbor[0], neighbor[1]):
                tentative_g_score = g_score[current_node] + 1

                if neighbor not in g_score or tentative_g_score < g_score[neighbor]:
                    came_from[neighbor] = current_node
                    g_score[neighbor] = tentative_g_score
                    f_score[neighbor] = tentative_g_score + heuristic(neighbor, end)
                    heapq.heappush(open_set, (f_score[neighbor], neighbor))

    return None
